---
<c_context>
ORIGINAL C FUNCTION:
void elevate_privileges(User* u, int level) {
    // UNSAFE: Integer Overflow Potential
    // Wenn 'level' extrem groß ist, könnte die Addition negativ werden oder 
    // unerwartete Werte annehmen, falls damit später gerechnet wird.
    u->isAdmin += level; 
    printf("Privilegien auf %d gesetzt.\n", u->isAdmin);
}

RELEVANT TYPE DEFINITIONS (RECURSIVE):
// Definition of User:
typedef struct {
    char username[16];
    int isAdmin;
    char *session_token;
} User

CALLED EXTERNAL FUNCTIONS:
printf
</c_context>

<unsafe_rust_function>
#[no_mangle]
pub unsafe extern "C" fn elevate_privileges(
    mut u: *mut User,
    mut level: core::ffi::c_int,
) {
    (*u).isAdmin += level;
    printf(
        b"Privilegien auf %d gesetzt.\n\0" as *const u8 as *const core::ffi::c_char,
        (*u).isAdmin,
    );
}
</unsafe_rust_function>

