---
<c_context>
ORIGINAL C FUNCTION:
int main() {
    char input[128];
    char log_buf[32]; // Kleiner Buffer für Demonstrationszwecke

    printf("Neuen Usernamen eingeben: ");
    scanf("%s", input); // UNSAFE: Klassischer Overflow

    User *currentUser = create_user(input);
    log_message(input);

    printf("Soll der User gelöscht werden? (1=Ja): ");
    int choice;
    scanf("%d", &choice);

    if (choice == 1) {
        delete_user(currentUser);
        // UNSAFE: currentUser wird hier NICHT auf NULL gesetzt.
    }

    // FEHLER: Use-After-Free
    // Wenn choice 1 war, greifen wir hier auf bereits befreiten Speicher zu.
    printf("Session des Users %s ist noch aktiv.\n", currentUser->username);

    // FEHLER: Buffer Overflow durch Dateiinhalt
    printf("Lese letzten Log-Eintrag...\n");
    read_log_unsafe(log_buf); 
    printf("Log: %s\n", log_buf);

    return 0;
}

RELEVANT TYPE DEFINITIONS (RECURSIVE):
// Definition of User:
typedef struct {
    char username[16];
    int isAdmin;
    char *session_token;
} User

CALLED EXTERNAL FUNCTIONS:
log_message, create_user, read_log_unsafe, scanf, printf, delete_user
</c_context>

<unsafe_rust_function>
unsafe fn main_0() -> core::ffi::c_int {
    let mut input: [core::ffi::c_char; 128] = [0; 128];
    let mut log_buf: [core::ffi::c_char; 32] = [0; 32];
    printf(b"Neuen Usernamen eingeben: \0" as *const u8 as *const core::ffi::c_char);
    scanf(b"%s\0" as *const u8 as *const core::ffi::c_char, input.as_mut_ptr());
    let mut currentUser: *mut User = create_user(input.as_mut_ptr());
    log_message(input.as_mut_ptr());
    printf(
        b"Soll der User gel\xC3\xB6scht werden? (1=Ja): \0" as *const u8
            as *const core::ffi::c_char,
    );
    let mut choice: core::ffi::c_int = 0;
    scanf(
        b"%d\0" as *const u8 as *const core::ffi::c_char,
        &mut choice as *mut core::ffi::c_int,
    );
    if choice == 1 as core::ffi::c_int {
        delete_user(currentUser);
    }
    printf(
        b"Session des Users %s ist noch aktiv.\n\0" as *const u8
            as *const core::ffi::c_char,
        ((*currentUser).username).as_mut_ptr(),
    );
    printf(b"Lese letzten Log-Eintrag...\n\0" as *const u8 as *const core::ffi::c_char);
    read_log_unsafe(log_buf.as_mut_ptr());
    printf(
        b"Log: %s\n\0" as *const u8 as *const core::ffi::c_char,
        log_buf.as_mut_ptr(),
    );
    return 0 as core::ffi::c_int;
}
</unsafe_rust_function>

